async function countUnreadNotifications(user_id) {
  try {
    const [{ count: generalCount }, { count: agreementCount }] = await Promise.all([
      supabase.from("notifications").select("id", { count: "exact", head: true }).eq("user_id", user_id).eq("read", false),
      supabase.from("agreement_notifications").select("id", { count: "exact", head: true }).eq("recipient_id", user_id).eq("is_actioned", false)
    ]);
    return (generalCount || 0) + (agreementCount || 0);
  } catch (e) {
    console.warn(e);
    return 0;
  }
}
